        "raw_expr": "(MEASURE(difot_actual) - MEASURE(difot_actual_py)) * 100",
        "comment": "DIFOT vs Prior Year = (Actual - PY) * 100"
      },
      {
        "name": "dif_vs_py",
        "raw_expr": "(MEASURE(dif_actual) - MEASURE(dif_actual_py)) * 100",
        "comment": "DIF vs Prior Year = (Actual - PY) * 100"
      },
      {
        "name": "ot_vs_py",
        "raw_expr": "(MEASURE(ot_actual) - MEASURE(ot_actual_py)) * 100",
        "comment": "OT vs Prior Year = (Actual - PY) * 100"
      },
      {
        "name": "ai_vs_py",
        "raw_expr": "(MEASURE(ai_actual) - MEASURE(ai_actual_py)) * 100",
        "comment": "AI vs Prior Year = (Actual - PY) * 100"
      },
      {
        "name": "wc_ytd_inventory_days_py",
        "raw_expr": "SUM(source.runningtotal) FILTER (WHERE source.bic_csubkbi = 'total_inventory_report' AND source.bic_chversion = '0000') / NULLIF(SUM(source.runningtotal) FILTER (WHERE source.bic_csubkbi = 'denomfor_inventory_days' AND source.bic_chversion = '0000'), 0)",
        "comment": "YTD Inventory days Prior Year (trailing 12 month window)",
        "window": {
          "order": "fiscper",
          "range": "trailing 12 month",
          "semiadditive": "last"
        }
      }
    ],
    "FT_PE009": [
      {
        "name": "contrib_in_primary_pack_metal",
        "raw_expr": "SUM(source.recycle_content_avg_sales_metal_hidden) * SUM(source.weight_metal_hidden) / NULLIF(SUM(source.sales_metal_hidden) * 100, 0) * SUM(source.sales_metal_hidden) / NULLIF(1000000, 0)",
        "comment": "Material contribution in primary pack metal (SUMX\u2192pre-aggregated)"
      },
      {
        "name": "contrib_in_primary_pack_glass",
        "raw_expr": "SUM(source.recycle_content_avg_sales_glass_hidden) * SUM(source.weight_glass_hidden) / NULLIF(SUM(source.sales_glass_hidden) * 100, 0) * SUM(source.sales_glass_hidden) / NULLIF(1000000, 0)",
        "comment": "Material contribution in primary pack glass (SUMX\u2192pre-aggregated)"
      },
      {
        "name": "wa_rpet_chip_pct",
        "raw_expr": "SUM(source.rpet_chip_pct_hidden) / NULLIF(SUM(source.sales_pet_hidden), 0)",
        "comment": "WA rPET chip %"
      },
      {
        "name": "wa_rpet_flake_pct",
        "raw_expr": "SUM(source.rpet_flake_pct_hidden) / NULLIF(SUM(source.sales_pet_hidden), 0)",
        "comment": "WA rPET flake %"
      },
      {
        "name": "wa_pet_meltin_ob_oil_based_pct",
        "raw_expr": "SUM(source.pet_meltin_ob_oil_based_pct_hidden) / NULLIF(SUM(source.sales_pet_hidden), 0)",
        "comment": "WA PET Meltin OB Oil-Based %"
      },
      {
        "name": "wa_recycled_content_glass_pct",
        "raw_expr": "SUM(source.recycle_content_avg_sales_glass_hidden) / NULLIF(SUM(source.sales_glass_hidden), 0)",
        "comment": "WA Recycled Content Glass %"
      },
      {
        "name": "wa_recycled_content_metal_pct",
        "raw_expr": "SUM(source.recycle_content_avg_sales_metal_hidden) / NULLIF(SUM(source.sales_metal_hidden), 0)",
        "comment": "WA Recycled Content Metal %"
      },
      {
        "name": "wa_raw_material_weight_g",
        "raw_expr": "SUM(source.weight_g_sales_hidden) / NULLIF(SUM(source.sales_volume_in_bottles_number_in_millions), 0)",
        "comment": "WA Raw Material Weight (g)"
      },
      {
        "name": "rpet_chip_gram_per_one_preform",
        "raw_expr": "MEASURE(wa_rpet_chip_pct) * MEASURE(wa_raw_material_weight_g)",
        "comment": "rPET Chip gram per one preform"
      },
      {
        "name": "rpet_flake_gram_per_one_preform",
        "raw_expr": "MEASURE(wa_rpet_flake_pct) * MEASURE(wa_raw_material_weight_g)",
        "comment": "rPET Flake gram per one preform"
      },
      {
        "name": "pet_meltin_oil_based",
        "raw_expr": "MEASURE(wa_pet_meltin_ob_oil_based_pct) * MEASURE(wa_raw_material_weight_g)",
        "comment": "PET Meltin Oil-Based"
      },
      {
        "name": "mat_contr_in_prim_pack_glass",
        "raw_expr": "MEASURE(wa_recycled_content_glass_pct)*SUM(source.weight_glass_hidden) / NULLIF(SUM(source.sales_glass_hidden) * 100, 0)",
        "comment": "Mat. contr in prim pack glass"
      },
      {
        "name": "mat_contr_in_prim_pack_met",
        "raw_expr": "MEASURE(wa_recycled_content_metal_pct)*SUM(source.weight_metal_hidden) / NULLIF(SUM(source.sales_metal_hidden) * 100, 0)",
        "comment": "Mat. contr in prim pack metal"
      },
      {
        "name": "mat_cont_in_primary_pack_pet_meltin_ob",
        "raw_expr": "MEASURE(pet_meltin_oil_based)*SUM(source.sales_pet_hidden) / NULLIF(1000000, 0)",
        "comment": "Mat Cont primary pack PET Meltin OB"
      },
      {
        "name": "mat_cont_in_primary_pack_rpet_chip",
        "raw_expr": "MEASURE(rpet_chip_gram_per_one_preform)*SUM(source.sales_pet_hidden) / NULLIF(1000000, 0)",
        "comment": "Mat Cont primary pack rPET Chip"
      },
      {
        "name": "mat_cont_in_primary_pack_rpet_flake",
        "raw_expr": "MEASURE(rpet_flake_gram_per_one_preform)*SUM(source.sales_pet_hidden) / NULLIF(1000000, 0)",
        "comment": "Mat Cont primary pack rPET Flake"
      },
      {
        "name": "recyclable_content_on_market_tons",
        "raw_expr": "MEASURE(contrib_in_primary_pack_glass) + MEASURE(contrib_in_primary_pack_metal) + MEASURE(mat_cont_in_primary_pack_pet_meltin_ob) + MEASURE(mat_cont_in_primary_pack_rpet_chip) + MEASURE(mat_cont_in_primary_pack_rpet_flake)",
        "comment": "Recyclable content on market (Tons) = sum of all material contributions"
      }
    ],
    "FT_BPC003": [
      {
        "name": "cost_supply_per_uc_actual",
        "raw_expr": "SUM(source.value) FILTER (WHERE source.bic_chversion = '0000' AND source.fis_code_parent IN ('DCD2','DHF2')) / NULLIF(SUM(co012.volume_in_uc), 0)",
        "comment": "Cost to Supply per Unit Case (Actuals) \u2014 SWITCH decomposition"
      },
