        "name": "cost_supply_pct_nsr_actual",
        "raw_expr": "SUM(source.value) FILTER (WHERE source.bic_chversion = '0000' AND source.fis_code_parent IN ('DCD2','DHF2')) / NULLIF(SUM(co012.net_sales_revenue), 0)",
        "comment": "Cost to Supply % NSR (Actuals) \u2014 SWITCH decomposition"
      },
      {
        "name": "prod_oh_per_uc_actual",
        "raw_expr": "SUM(source.value) FILTER (WHERE source.bic_chversion = '0000' AND source.fis_code IN ('DCC3','DCC1','DCCE','DCCN','DCCY','DCEJ','DCEZ','DCEK')) / NULLIF(SUM(co012.volume_in_uc), 0)",
        "comment": "Production Overhead per Unit Case (Actuals) \u2014 SWITCH decomposition"
      },
      {
        "name": "prod_oh_pct_nsr_actual",
        "raw_expr": "SUM(source.value) FILTER (WHERE source.bic_chversion = '0000' AND source.fis_code IN ('DCC3','DCC1','DCCE','DCCN','DCCY','DCEJ','DCEZ','DCEK')) / NULLIF(SUM(co012.net_sales_revenue), 0)",
        "comment": "Production Overhead % NSR (Actuals) \u2014 SWITCH decomposition"
      },
      {
        "name": "sc_cost_per_uc_actual",
        "raw_expr": "SUM(source.value) FILTER (WHERE source.bic_chversion = '0000' AND source.fis_code IN ('DCC3','DCC1','DCCE','DCCN','DCCY','DCEJ','DCEZ','DCEK','DCD2','DHG2','DHH2')) / NULLIF(SUM(co012.volume_in_uc), 0)",
        "comment": "Supply Chain Cost per Unit Case (Actuals) \u2014 SWITCH decomposition"
      },
      {
        "name": "sc_cost_pct_nsr_actual",
        "raw_expr": "SUM(source.value) FILTER (WHERE source.bic_chversion = '0000' AND source.fis_code IN ('DCC3','DCC1','DCCE','DCCN','DCCY','DCEJ','DCEZ','DCEK','DCD2','DHG2','DHH2')) / NULLIF(SUM(co012.net_sales_revenue), 0)",
        "comment": "Supply Chain Cost % NSR (Actuals) \u2014 SWITCH decomposition"
      }
    ],
    "Fact_CO012_REBP": [
      {
        "name": "sc_prod_actual_bp",
        "raw_expr": "SUM(source.volume_in_uc) FILTER (WHERE source.bic_chversion = 'B000') / NULLIF(SUM(hr_a.khr004001_fte_total) FILTER (WHERE hr_a.bic_chversion = 'B000' AND hr_a.func_area IN ('Z320', 'Z110', 'Z120', 'Z310')) / NULLIF(1, 0), 0)",
